import { NextResponse } from 'next/server';
import { seedInitialCollections } from '@/lib/seed-firebase';

export async function GET() {
  try {
    await seedInitialCollections();
    return NextResponse.json({ success: true, message: 'Firebase collections seeded successfully' });
  } catch (error) {
    console.error('Seeding error:', error);
    return NextResponse.json({ success: false, error: 'Failed to seed collections' }, { status: 500 });
  }
}
